  1→/**
  2→ * GitHubProvider — PlatformProvider implementation wrapping the `gh` CLI.
  3→ *
  4→ * Owns all `gh` CLI calls for the orchestration layer. Skills continue
  5→ * to call `gh` directly for v1 (see Non-Goals in #368).
  6→ */
  7→
  8→import { execSync } from "child_process";
  9→import { spawnSync } from "child_process";
 10→import type {
 11→  PlatformProvider,
 12→  Issue,
 13→  CreatePROptions,
 14→  PRInfo,
 15→  PRStatus,
 16→  Comment,
 17→} from "./platform-provider.js";
 18→
 19→export class GitHubProvider implements PlatformProvider {
 20→  name = "github";
 21→
 22→  async fetchIssue(id: string): Promise<Issue> {
 23→    const output = execSync(
 24→      `gh issue view ${id} --json number,title,body,labels,state`,
 25→      { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"] },
 26→    );
 27→    const data = JSON.parse(output);
 28→    return {
 29→      id: String(data.number),
 30→      number: data.number,
 31→      title: data.title,
 32→      body: data.body,
 33→      labels: (data.labels ?? []).map((l: { name: string }) => l.name),
 34→      state: data.state.toLowerCase() as "open" | "closed",
 35→    };
 36→  }
 37→
 38→  async postComment(issueId: string, body: string): Promise<void> {
 39→    spawnSync("gh", ["issue", "comment", issueId, "--body", body], {
 40→      stdio: "pipe",
 41→      timeout: 15000,
 42→    });
 43→  }
 44→
 45→  async addLabel(issueId: string, label: string): Promise<void> {
 46→    spawnSync("gh", ["issue", "edit", issueId, "--add-label", label], {
 47→      stdio: "pipe",
 48→      timeout: 15000,
 49→    });
 50→  }
 51→
 52→  async removeLabel(issueId: string, label: string): Promise<void> {
 53→    spawnSync("gh", ["issue", "edit", issueId, "--remove-label", label], {
 54→      stdio: "pipe",
 55→      timeout: 15000,
 56→    });
 57→  }
 58→
 59→  async createPR(opts: CreatePROptions): Promise<PRInfo> {
 60→    const result = spawnSync(
 61→      "gh",
 62→      [
 63→        "pr",
 64→        "create",
 65→        "--title",
 66→        opts.title,
 67→        "--body",
 68→        opts.body,
 69→        "--head",
 70→        opts.head,
 71→        "--base",
 72→        opts.base,
 73→      ],
 74→      { stdio: "pipe", timeout: 30000 },
 75→    );
 76→
 77→    if (result.status !== 0) {
 78→      const error = result.stderr?.toString().trim() ?? "Unknown error";
 79→      throw new Error(`gh pr create failed: ${error}`);
 80→    }
 81→
 82→    const output = result.stdout?.toString().trim() ?? "";
 83→    const urlMatch = output.match(/https:\/\/github\.com\/[^\s]+\/pull\/(\d+)/);
 84→
 85→    if (urlMatch) {
 86→      return {
 87→        number: parseInt(urlMatch[1], 10),
 88→        url: urlMatch[0],
 89→      };
 90→    }
 91→
 92→    throw new Error(
 93→      `PR created but could not extract URL from output: ${output}`,
 94→    );
 95→  }
 96→
 97→  async getPRStatus(prId: string): Promise<PRStatus> {
 98→    const result = spawnSync(
 99→      "gh",
100→      ["pr", "view", prId, "--json", "state", "-q", ".state"],
101→      { stdio: "pipe", timeout: 10000 },
102→    );
103→
