      `gh issue view ${issueNumber} --json comments --jq '[.comments[].body]'`,
      { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"] },
    );

    const bodies: string[] = JSON.parse(output);
    const comments = bodies.map((body) => ({ body }));
