 */

import chalk from "chalk";
import { execSync } from "child_process";
import { ui, colors } from "../lib/cli-ui.js";
import { fileExists, isExecutable } from "../lib/fs.js";
import { getManifest } from "../lib/manifest.js";
import {
  commandExists,
